vertexScript:
varying vec2 vTexCoord;
varying float vAO;
varying float vTextureIndex;
attribute float aPackedData;
attribute float aTextureIndex;

void main() {
    uint packed = uint(aPackedData);
    float x = float((packed >> 26u) & 0x3Fu);
    float y = float((packed >> 20u) & 0x3Fu);
    float z = float((packed >> 14u) & 0x3Fu);
    float u = float((packed >> 13u) & 0x01u);
    float v = float((packed >> 12u) & 0x01u);
    float ao = float((packed >> 10u) & 0x03u);

    vTexCoord = vec2(u, v);
    vAO = 0.7 + ao * 0.1;
    vTextureIndex = aTextureIndex;

    gl_Position = projectionMatrix * modelViewMatrix * vec4(x, y, z, 1.0);
}

fragmentScript:
uniform sampler2D uTextureAtlas;
varying vec2 vTexCoord;
varying float vAO;
varying float vTextureIndex;

void main() {
    vec4 texColor = texture2D(uTextureAtlas, vTexCoord);
    gl_FragColor = vec4(texColor.rgb * vAO, texColor.a);
}
